import sys

def time_to_minutes(t):
    h, m = t.split(':')
    return int(h) * 60 + int(m)

total = 0
for line in sys.argv[1].splitlines():
    line = line.strip()
    if line:
        start, end = line.split('-')
        total += time_to_minutes(end) - time_to_minutes(start)

sys.stdout.write(str(total) + '\n')

